constexpr int32_t BUFFER_NUM = 2;

class KernelCa6k00282Custom {
public:
    __aicore__ inline KernelCa6k00282Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t spatialSize,
                                uint32_t tileLength, uint32_t blockDim,
                                float eps)
    {
        totalLen_ = totalLength;
        spatialSize_ = spatialSize;
        tileLen_ = tileLength;
        blockDim_ = blockDim;
        eps_ = eps;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue_, 1, tileLen_ * sizeof(float));
        pipe_.InitBuffer(meanVarTensor_, 1, 1 * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (totalLen_ == 0 || spatialSize_ == 0 || tileLen_ == 0) return;

        uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());
        uint32_t batchChannels = totalLen_ / spatialSize_;
        if (blockIdx >= batchChannels) return;

        uint32_t baseOffset = blockIdx * spatialSize_;

        // First pass: compute sum and sum of squares
        float sum = 0.0f;
        float sumSq = 0.0f;
        uint32_t remaining = spatialSize_;
        uint32_t offset = 0;
        while (remaining > 0) {
            uint32_t curLen = (remaining >= tileLen_) ? tileLen_ : remaining;
            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[baseOffset + offset], curLen);
            inQueueX_.EnQue(xLocal);
            xLocal = inQueueX_.DeQue<float>();

            // tile sum
            AscendC::LocalTensor<float> tileSumTensor = tmpQueue_.AllocTensor<float>();
            AscendC::ReduceAdd(tileSumTensor, xLocal, curLen);
            float tileSum = tileSumTensor.GetValue(0);
            tmpQueue_.FreeTensor(tileSumTensor);

            // tile sum of squares
            AscendC::LocalTensor<float> sqTensor = tmpQueue_.AllocTensor<float>();
            AscendC::Mul(sqTensor, xLocal, xLocal, curLen);
            AscendC::ReduceAdd(sqTensor, sqTensor, curLen);
            float tileSumSq = sqTensor.GetValue(0);
            tmpQueue_.FreeTensor(sqTensor);

            sum += tileSum;
            sumSq += tileSumSq;

            inQueueX_.FreeTensor(xLocal);
            remaining -= curLen;
            offset += curLen;
        }

        float mean = sum / static_cast<float>(spatialSize_);
        float var = sumSq / static_cast<float>(spatialSize_) - mean * mean;
        // sqrt via scalar local tensor (ensure eps positive)
        AscendC::LocalTensor<float> varTensor = meanVarTensor_.Get<float>();
        varTensor.SetValue(0, var + eps_);
        AscendC::Sqrt(varTensor, varTensor, 1);
        float invStd = 1.0f / varTensor.GetValue(0);

        // Second pass: normalize
        remaining = spatialSize_;
        offset = 0;
        while (remaining > 0) {
            uint32_t curLen = (remaining >= tileLen_) ? tileLen_ : remaining;
            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[baseOffset + offset], curLen);
            inQueueX_.EnQue(xLocal);
            xLocal = inQueueX_.DeQue<float>();

            AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();
            AscendC::Sub(yLocal, xLocal, mean, curLen);
            AscendC::Muls(yLocal, yLocal, invStd, curLen);

            outQueueY_.EnQue<float>(yLocal);
            AscendC::LocalTensor<float> yOut = outQueueY_.DeQue<float>();
            AscendC::DataCopy(yGm_[baseOffset + offset], yOut, curLen);
            outQueueY_.FreeTensor(yOut);
            inQueueX_.FreeTensor(xLocal);

            remaining -= curLen;
            offset += curLen;
        }
    }

private:
